package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;

import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

class ReflectionAccessFilterHelperTest {

  @Test
  void testIsAndroidType_withAndroidClassName() throws Exception {
    // Use reflection to access private static method isAndroidType(String)
    var method = ReflectionAccessFilterHelper.class.getDeclaredMethod("isAndroidType", String.class);
    method.setAccessible(true);

    // Typical Android class prefix
    String androidClassName = "android.app.Activity";
    boolean result = (boolean) method.invoke(null, androidClassName);
    assertTrue(result);

    // Another Android package prefix
    androidClassName = "androidx.appcompat.widget.AppCompatButton";
    result = (boolean) method.invoke(null, androidClassName);
    assertTrue(result);

    // Android internal package
    androidClassName = "com.android.internal.R";
    result = (boolean) method.invoke(null, androidClassName);
    assertTrue(result);
  }

  @Test
  void testIsAndroidType_withNonAndroidClassName() throws Exception {
    var method = ReflectionAccessFilterHelper.class.getDeclaredMethod("isAndroidType", String.class);
    method.setAccessible(true);

    // Java standard class
    String javaClassName = "java.lang.String";
    boolean result = (boolean) method.invoke(null, javaClassName);
    assertFalse(result);

    // Random class name
    String randomClassName = "com.example.MyClass";
    result = (boolean) method.invoke(null, randomClassName);
    assertFalse(result);

    // Null or empty string edge cases
    result = (boolean) method.invoke(null, "");
    assertFalse(result);

    result = (boolean) method.invoke(null, (Object) null);
    assertFalse(result);
  }

  @Test
  void testIsAndroidType_withClassObject() {
    // Test with Android class name via public method isAndroidType(Class<?>)
    // Use a real class with android-like name via anonymous subclass trick

    Class<?> androidLikeClass = new Object() {
      @Override
      public String toString() {
        return "android.some.FakeClass";
      }
    }.getClass();
    // Override getName() by subclassing Class is impossible, so instead we create a dynamic proxy-like approach:
    // But since Class cannot be mocked, we test indirectly by creating a dummy class in android package.
    // Instead, test with a real class and test the public method with a string that starts with "android"

    // So test directly the string method instead for this case:
    // This test is not applicable for Class<?> parameter with mocking, so test with real classes only.

    // Android-like class name string test (covered in other tests)

    // Standard Java class
    boolean result = ReflectionAccessFilterHelper.isAndroidType(String.class);
    assertFalse(result);

    // Custom class outside android package
    result = ReflectionAccessFilterHelper.isAndroidType(ReflectionAccessFilterHelper.class);
    assertFalse(result);
  }
}
